#include<bits/stdc++.h>
using namespace std;

const int N = 3e6 + 5;

int a[N], st[N], ans[N];
int top;

int main()
{
    int n;
    cin >> n;
    for(int i = 1; i <= n; i++)
        cin >> a[i];
    for(int i = n; i >= 1; i--)
    {
        while(top && a[st[top]] <= a[i])
            top--;
        ans[i] = st[top];
        st[++top] = i;
    }
    for(int i = 1; i <= n; i++)
        cout << ans[i] << ' ';
}
